# -*- coding: utf-8 -*-
"""Loghi (base64) per intestazioni grafiche: The Organism, PNEV, MAPS."""
import base64 as _b

LOGO_ORGANISM_B64 = ""
LOGO_PNEV_B64 = ""
LOGO_MAPS_B64 = ""

LOGO_ORGANISM = _b.b64decode(LOGO_ORGANISM_B64)
LOGO_PNEV = _b.b64decode(LOGO_PNEV_B64)
LOGO_MAPS = _b.b64decode(LOGO_MAPS_B64)
